  if (
    showResult &&
    isRescueConcluded &&
    !alreadyMarkedRef.current &&
    hasRedeemed !== true
  ) {
    alreadyMarkedRef.current = true;
    markAsRedeemed().catch(() => {});   // <-- updates permission store
  }
}, [
